var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"으흠. 융합체들은 다 당했나 보네.","JPN":"ふうん。融合体はみんなやられたみたいね。","ENG":"Hmm... Looks like the hybriders couldn’t make it.","TWN":"嗯哼，融合體好像都不行咧？"},"stage":{"bg":"GRONIA_STREET","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"이래서야, 실패작. 저런 짐승들 따위로는 결국 당해내지 못해.","JPN":"わかった？　失敗作。あんな獣などでは敵うはずもないわ。","ENG":"Useless failed products. These kinds of beasts are no match for them.","TWN":" 所以才說是失敗品的嘛～結果那些畜生還是招架不住。"},"stage":{"bg":"GRONIA_STREET","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"풍부한 경험과 강력한 힘. 멸망에 대처하려면 야속하게도 두 마리 토끼를 다 잡아야 하는 법이라구.","JPN":"豊富な経験と強力な力。滅亡に対応するためには、くやしいけれど両方とも手にする必要があるのよね。","ENG":"Abundant experience and incredible power. Both are needed to fight against inevitable ruin.","TWN":"豐富的經驗和強大的力量，要應對滅亡，就必須二者兼備。"},"stage":{"bg":"GRONIA_STREET","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"구질구질하게 변명하지 마, 셰나.","JPN":"ぐずぐず言いわけしないで、シェナ。","ENG":"Don’t make such dirty excuses, Shena.","TWN":"說那麼多廢話幹嘛，世娜。"},"stage":{"bg":"GRONIA_STREET","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"너희가 멘탈 프린팅에 집착하는 까닭은 결국 원본이 남긴 감정 탓 아니려나?","JPN":"あなたたちがメンタル・プリンティングにこだわる理由は、結局オリジナルが残した感情のせいじゃないの？","ENG":"After all, aren’t you obsessed with Mental Printing because of the feelings left by the original?","TWN":"你們之所以如此執著於智力複印，不就是因為本體留下的情感嗎？"},"stage":{"bg":"GRONIA_STREET","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"뭘 세상을 위해 숭고한 희생이라도 하는 척 지껄이니?","JPN":"何、世界のために崇高な犠牲を払ってやってるみたいな言い方してるのよ？","ENG":"What are you babbling on about, pretending to make a noble sacrifice for the sake of the world?","TWN":"講得一副多偉大，好像是為世界犧牲一樣？"},"stage":{"bg":"GRONIA_STREET","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"물론 너희 세상은 아니지.","JPN":"もちろんあなたたちの世界ではないわね。","ENG":"Not your world, of course.","TWN":"只是不是為你們的世界犧牲。"},"stage":{"bg":"GRONIA_STREET","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"하지만 알고 있을까? 그 <color=#ffd34c>원본</color> 년들 탓에 완성될 가망도 없는 연구에 매달려야 하는 우리 기분은?","JPN":"でもわかってるのかしら。その<color=#ffd34c>オリジナル</color>のせいで完成の見込みもない研究にすがる私たちの気持ちを。","ENG":"But can you understand how it feels? Having to stick with a hopeless research project because of those <color=#ffd34c>original</color> scumbags?","TWN":"但你知道嗎？因為<color=#ffd34c>本體</color>關係，明明沒有成功的希望，卻還是要埋首於研究。"},"stage":{"bg":"GRONIA_STREET","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"부질없는 짓이란 걸 알면서도 너희들이 숨을 쉬듯 멘탈 프린팅에만 매달리는 기분을?","JPN":"儚いとわかっていてもあなたたちが呼吸をするように、ただメンタル・プリンティングだけにすがる気持ちを。","ENG":"How it feels, when even though you know it’s useless, you still hold onto Mental Printing as though you needed it as much as you need to breathe?","TWN":"明知道是徒勞無功，卻依舊只能執著於智力複印的心情你懂嗎？"},"stage":{"bg":"GRONIA_STREET","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"어차피 실패작인 네가 이해할 수 있는 날은 오지 않겠지만!","JPN":"どうせ失敗作のあなたが理解できる日は来ないでしょうけど！","ENG":"In any case you will never be able to understand, failed product!","TWN":"像你這種失敗品是永遠都不會懂的！"},"stage":{"bg":"GRONIA_STREET","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"……궁지에 몰리니 동정심이라도 사려고?","JPN":"……追いつめられて哀れを誘うつもり？","ENG":"...You expect me to feel sorry for you?","TWN":"……現在是走投無路，所以想改用苦肉計嗎？"},"stage":{"bg":"GRONIA_STREET","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"끝까지 역겹네. 그런 가증스러운 짓을 너희 상대하면서 한두 번 본 줄 알아?","JPN":"最後まで吐き気がするね。あなたたちを相手する間、その憎たらしい演技は飽きるほど見て来たの。","ENG":"You disgust me. Do you know how many times I’ve seen you do such deceitful things ever since I started opposing you?","TWN":"到現在還在死鴨子嘴硬，你以為我不知道你們幹的那些壞事嗎？"},"stage":{"bg":"GRONIA_STREET","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"아차. 들켰나.","JPN":"まあ。バレた？","ENG":"Whoops. You got me.","TWN":"哎呀，被發現啦？"},"stage":{"bg":"GRONIA_STREET","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"후우…….","JPN":"ふう……","ENG":"Haa…","TWN":"呼……"},"stage":{"bg":"GRONIA_STREET","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"예고르, 셰나의 반응은?","JPN":"イェゴール、シェナの反応は？","ENG":"Yegor, Shena’s signal response?","TWN":"伊高爾，世娜的反應呢？"},"stage":{"bg":"GRONIA_STREET","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"반경 40km 내에서 감지되지 않습니다.","JPN":"半径40km内では感知されていません。","ENG":"It is not detected within a 40km radius.","TWN":"在半徑40km內都沒有感應到。"},"stage":{"bg":"GRONIA_STREET","slots":{"L":null,"C":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"관리국 정찰위성의 관측 결과……. 손상이 심해 이면세계로 퇴거된 모양입니다.","JPN":"管理局の偵察衛星の観測結果……ひどく損傷し、裏世界へと退去したようです。","ENG":"According to the Administration’s surveillance satellite... It seems the damage was so severe she was displaced to Counterside.","TWN":"根據管理局偵查衛星的偵測結果……似乎是受損太嚴重，暫時退到異界的樣子。"},"stage":{"bg":"GRONIA_STREET","slots":{"L":null,"C":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};